export interface Customer {
  yearsWithMHPCO: number;
}

export interface QuoteStep {
  op: "quote";
  items: Array<Record<string, unknown>>;
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: {
    cause: string;
    damages: Array<{ itemType: string; amount: number }>;
  };
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export type StepResult =
  | { premium: number }
  | { payout: number; remainingCap: number };

export interface ScenarioResult {
  results: StepResult[];
}

const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const baseFor = (item: Record<string, unknown>): number =>
  BASE_PREMIUM[item.type as string] ?? 0;

const quotePremium = (step: QuoteStep): StepResult => {
  const baseTotal = step.items.reduce((sum, item) => sum + baseFor(item), 0);
  const firstInsuranceSurcharge = baseTotal * 0.1;
  return { premium: baseTotal + firstInsuranceSurcharge + PROCESSING_FEE };
};

const processStep = (step: Step): StepResult => {
  if (step.op === "quote") return quotePremium(step);
  return { payout: 0, remainingCap: 0 };
};

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map(processStep),
});

